40в†’/** @internal Log a non-fatal warning: one-line summary always, detail in verbose. */
41в†’export function logNonFatalWarning(
42в†’  message: string,
43в†’  error: unknown,
44в†’  verbose: boolean,
45в†’): void {
46в†’  console.log(chalk.yellow(message));
47в†’  if (verbose) {
