50в†’}

  1в†’/**
  2в†’ * Assess Comment Parser
  3в†’ *
  4в†’ * Detects and parses /assess command output from GitHub issue comments.
  5в†’ * This is the unified parser that handles both the new /assess format
  6в†’ * and the legacy /solve format for backward compatibility.
  7в†’ *
  8в†’ * When an assess comment exists, its phase recommendations take precedence
  9в†’ * over content analysis (but not over labels).
 10в†’ *
 11в†’ * @example
 12в†’ * ```typescript
 13в†’ * import { findAssessComment, parseAssessWorkflow } from './assess-comment-parser';
 14в†’ *
 15в†’ * const comments = [
 16в†’ *   { body: "Some regular comment" },
 17в†’ *   { body: "## Assess Analysis\n\nв†’ PROCEED вЂ” Ready.\n\n<!-- assess:phases=spec,exec,qa -->" },
 18в†’ * ];
 19в†’ *
 20в†’ * const assessComment = findAssessComment(comments);
 21в†’ * if (assessComment) {
 22в†’ *   const workflow = parseAssessWorkflow(assessComment.body);
 23в†’ *   // workflow: { phases: ['spec', 'exec', 'qa'], action: 'PROCEED', ... }
 24в†’ * }
 25в†’ * ```
 26в†’ */
 27в†’
 28в†’import type { Phase } from "./workflow/types.js";
 29в†’import type { PhaseSignal } from "./phase-signal.js";
 30в†’
 31в†’/**
 32в†’ * The 6 fixed actions that /assess can recommend
 33в†’ */
 34в†’export type AssessAction =
 35в†’  | "PROCEED"
 36в†’  | "CLOSE"
 37в†’  | "MERGE"
 38в†’  | "REWRITE"
 39в†’  | "CLARIFY"
 40в†’  | "PARK";
 41в†’
 42в†’/**
 43в†’ * Result of parsing an assess comment (superset of SolveWorkflowResult)
 44в†’ */
 45в†’export interface AssessWorkflowResult {
 46в†’  /** Phases recommended by assess (only meaningful for PROCEED) */
 47в†’  phases: Phase[];
 48в†’  /** Whether quality loop is recommended */
 49в†’  qualityLoop: boolean;
 50в†’  /** The issue numbers mentioned in the assess comment */
 51в†’  issueNumbers: number[];
 52в†’  /** Raw workflow string (e.g., "spec в†’ exec в†’ qa") */
 53в†’  workflowString?: string;
 54в†’  /** The recommended action (one of the 6 fixed actions) */
 55в†’  action?: AssessAction;
 56в†’}
 57в†’
 58в†’/**
 59в†’ * Backward-compatible alias for AssessWorkflowResult
 60в†’ */
 61в†’export type SolveWorkflowResult = AssessWorkflowResult;
 62в†’
 63в†’/**
 64в†’ * Comment structure (simplified from GitHub API)
 65в†’ */
 66в†’export interface IssueComment {
 67в†’  body: string;
 68в†’  author?: {
 69в†’    login: string;
 70в†’  };
 71в†’  createdAt?: string;
 72в†’}
 73в†’
 74в†’/**
 75в†’ * Markers that indicate an assess comment (new format)
 76в†’ */
 77в†’const ASSESS_MARKERS = [
 78в†’  "## Assess Analysis",
 79в†’  "## Assess Workflow",
 80в†’  "*Generated by `/assess",
 81в†’];
 82в†’
 83в†’/**
 84в†’ * Markers that indicate a solve comment (legacy format)
 85в†’ */
 86в†’const SOLVE_MARKERS = [
 87в†’  "## Solve Analysis",
 88в†’  "## Solve Workflow for Issues:",
 89в†’  "## Solve Workflow for Issue:",
 90в†’  "### Recommended Workflow",
 91в†’  "*рџ“ќ Generated by `/solve",
 92в†’];
 93в†’
 94в†’/**
 95в†’ * All markers (both assess and solve)
 96в†’ */
 97в†’const ALL_MARKERS = [...ASSESS_MARKERS, ...SOLVE_MARKERS];
 98в†’
 99в†’/**
100в†’ * Pattern to extract phases from workflow string
101в†’ * Matches: `/spec`, `/exec`, `/test`, `/qa`, etc.
102в†’ * Also matches without slash: `spec`, `exec`, `test`, `qa` (for arrow notation)
103в†’ */
104в†’const PHASE_PATTERN =
105в†’  /\/?(?<!\w)(spec|exec|test|qa|security-review|testgen|loop)(?!\w)/g;
106в†’
107в†’/**
108в†’ * Pattern to detect quality loop recommendation
109в†’ */
110в†’const QUALITY_LOOP_PATTERNS = [
111в†’  /quality\s*loop.*auto-enable/i,
112в†’  /--quality-loop/i,
113в†’  /quality\s*loop.*recommended/i,
114в†’  /enable.*quality\s*loop/i,
115в†’];
116в†’
117в†’/**
118в†’ * Pattern to extract structured data from HTML comment markers
119в†’ * Matches both: <!-- assess:phases=exec,qa --> and <!-- solve:phases=exec,qa -->
120в†’ */
121в†’const HTML_MARKER_PATTERN =
122в†’  /<!--\s*(?:assess|solve):(\w[\w-]*)=([\w,.-]*)\s*-->/g;
123в†’
124в†’/**
125в†’ * Pattern to extract assess-specific HTML markers (takes precedence)
126в†’ */
127в†’const ASSESS_HTML_MARKER_PATTERN = /<!--\s*assess:(\w[\w-]*)=([\w,.-]*)\s*-->/g;
128в†’
129в†’/**
130в†’ * Pattern to extract issue numbers from header
131в†’ * Matches: "## Solve Workflow for Issues: 123, 456" or "#123"
132в†’ */
133в†’const ISSUE_NUMBER_PATTERN = /#?(\d+)/g;
134в†’
135в†’/**
136в†’ * Valid assess actions
137в†’ */
138в†’const VALID_ACTIONS: AssessAction[] = [
139в†’  "PROCEED",
140в†’  "CLOSE",
141в†’  "MERGE",
142в†’  "REWRITE",
143в†’  "CLARIFY",
144в†’  "PARK",
145в†’];
146в†’
147в†’/**
148в†’ * Structured data extracted from HTML comment markers
149в†’ */
150в†’export interface AssessMarkers {
151в†’  /** Recommended phases */
152в†’  phases?: string[];
153в†’  /** Whether to skip spec */
154в†’  skipSpec?: boolean;
155в†’  /** Whether browser testing is needed */
156в†’  browserTest?: boolean;
157в†’  /** Whether quality loop is recommended */
158в†’  qualityLoop?: boolean;
159в†’  /** The recommended action */
160в†’  action?: AssessAction;
161в†’}
162в†’
163в†’/**
164в†’ * Backward-compatible alias for AssessMarkers
165в†’ */
166в†’export type SolveMarkers = AssessMarkers;
167в†’
168в†’// в”Ђв”Ђв”Ђ Detection Functions в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
169в†’
170в†’/**
171в†’ * Check if a comment is an assess command output (new format)
172в†’ */
173в†’export function isAssessComment(body: string): boolean {
174в†’  return ALL_MARKERS.some((marker) => body.includes(marker));
175в†’}
176в†’
177в†’/**
178в†’ * Check if a comment is a solve command output (legacy format)
179в†’ * @deprecated Use isAssessComment instead
180в†’ */
181в†’export function isSolveComment(body: string): boolean {
182в†’  return isAssessComment(body);
183в†’}
184в†’
185в†’/**
186в†’ * Find the most recent assess/solve comment from a list of comments
187в†’ */
188в†’export function findAssessComment(
189в†’  comments: IssueComment[],
190в†’): IssueComment | null {
191в†’  for (let i = comments.length - 1; i >= 0; i--) {
192в†’    if (isAssessComment(comments[i].body)) {
193в†’      return comments[i];
194в†’    }
195в†’  }
196в†’  return null;
197в†’}
198в†’
199в†’/**
200в†’ * Find the most recent solve comment from a list of comments
201в†’ * @deprecated Use findAssessComment instead
202в†’ */
203в†’export function findSolveComment(
204в†’  comments: IssueComment[],
205в†’): IssueComment | null {
206в†’  return findAssessComment(comments);
207в†’}
208в†’
209в†’// в”Ђв”Ђв”Ђ Parsing Functions в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
210в†’
211в†’/**
212в†’ * Parse phases from a workflow string
213в†’ */
214в†’function parseWorkflowString(workflowString: string): Phase[] {
215в†’  const phases: Phase[] = [];
216в†’  const matches = workflowString.matchAll(PHASE_PATTERN);
217в†’
218в†’  for (const match of matches) {
219в†’    const phase = match[1] as Phase;
220в†’    if (!phases.includes(phase)) {
221в†’      phases.push(phase);
222в†’    }
223в†’  }
224в†’
225в†’  return phases;
226в†’}
227в†’
228в†’/**
229в†’ * Parse HTML comment markers from a comment body
230в†’ *
231в†’ * Supports both `assess:` and `solve:` prefixes.
232в†’ * When both are present, `assess:` markers take precedence.
233в†’ */
234в†’export function parseAssessMarkers(body: string): AssessMarkers {
235в†’  const markers: AssessMarkers = {};
236в†’
237в†’  // First pass: collect all markers (both assess: and solve:)
238в†’  const allMatches = body.matchAll(HTML_MARKER_PATTERN);
239в†’  for (const match of allMatches) {
240в†’    applyMarker(markers, match[1], match[2]);
241в†’  }
242в†’
243в†’  // Second pass: assess: markers override solve: markers
244в†’  const assessMatches = body.matchAll(ASSESS_HTML_MARKER_PATTERN);
245в†’  for (const match of assessMatches) {
246в†’    applyMarker(markers, match[1], match[2]);
247в†’  }
248в†’
249в†’  return markers;
250в†’}
251в†’
252в†’/**
253в†’ * Apply a single marker key-value pair to the markers object
254в†’ */
255в†’function applyMarker(markers: AssessMarkers, key: string, value: string): void {
256в†’  switch (key) {
257в†’    case "phases":
258в†’      markers.phases = value.split(",").filter(Boolean);
259в†’      break;
260в†’    case "skip-spec":
261в†’      markers.skipSpec = value === "true";
262в†’      break;
263в†’    case "browser-test":
264в†’      markers.browserTest = value === "true";
265в†’      break;
266в†’    case "quality-loop":
267в†’      markers.qualityLoop = value === "true";
268в†’      break;
269в†’    case "action":
270в†’      if (VALID_ACTIONS.includes(value as AssessAction)) {
271в†’        markers.action = value as AssessAction;
272в†’      }
273в†’      break;
274в†’  }
275в†’}
276в†’
277в†’/**
278в†’ * Parse HTML comment markers (backward-compatible alias)
279в†’ * @deprecated Use parseAssessMarkers instead
280в†’ */
281в†’export function parseSolveMarkers(body: string): AssessMarkers {
282в†’  return parseAssessMarkers(body);
283в†’}
284в†’
285в†’/**
286в†’ * Parse an assess/solve comment to extract workflow information
287в†’ */
288в†’export function parseAssessWorkflow(body: string): AssessWorkflowResult {
289в†’  const result: AssessWorkflowResult = {
290в†’    phases: [],
291в†’    qualityLoop: false,
292в†’    issueNumbers: [],
293в†’  };
294в†’
295в†’  // Extract action from "в†’ ACTION вЂ” reason" line
296в†’  const actionMatch = body.match(
297в†’    /в†’\s*(PROCEED|CLOSE|MERGE|REWRITE|CLARIFY|PARK)\s*[вЂ”-]/,
298в†’  );
299в†’  if (actionMatch) {
300в†’    result.action = actionMatch[1] as AssessAction;
301в†’  }
302в†’
303в†’  // Extract issue numbers from header (both old and new formats)
304в†’  const headerMatch = body.match(
305в†’    /## (?:Assess|Solve) (?:Workflow for Issues?|Analysis)(?::\s*|\s+for\s+)([^\n]+)/i,
306в†’  );
307в†’  if (headerMatch) {
308в†’    const numberMatches = headerMatch[1].matchAll(ISSUE_NUMBER_PATTERN);
309в†’    for (const match of numberMatches) {
310в†’      const num = parseInt(match[1], 10);
311в†’      if (!isNaN(num) && !result.issueNumbers.includes(num)) {
312в†’        result.issueNumbers.push(num);
313в†’      }
314в†’    }
315в†’  }
316в†’
317в†’  // Try HTML comment markers first (most reliable, machine-readable)
318в†’  const markers = parseAssessMarkers(body);
319в†’
320в†’  // Action from markers overrides inline detection
321в†’  if (markers.action) {
322в†’    result.action = markers.action;
323в†’  }
324в†’
325в†’  if (markers.phases && markers.phases.length > 0) {
326в†’    result.phases = markers.phases as Phase[];
327в†’    result.workflowString = markers.phases.join(" в†’ ");
328в†’  }
329в†’
330в†’  if (markers.qualityLoop !== undefined) {
331в†’    result.qualityLoop = markers.qualityLoop;
332в†’  }
333в†’
334в†’  // If we got phases from markers, we're done with phase detection
335в†’  if (result.phases.length > 0) {
336в†’    return result;
337в†’  }
338в†’
339в†’  // Find workflow lines (e.g., "/spec 152" or "spec в†’ exec в†’ qa")
340в†’  const lines = body.split("\n");
341в†’
342в†’  // First pass: look for arrow notation (most reliable)
343в†’  for (const line of lines) {
344в†’    if (line.includes("в†’") || line.includes("->")) {
345в†’      const phases = parseWorkflowString(line);
346в†’      if (phases.length > 0) {
347в†’        result.phases = phases;
348в†’        result.workflowString = line.trim();
349в†’        break;
350в†’      }
351в†’    }
352в†’  }
353в†’
354в†’  // Second pass: if no arrow notation found, collect phases from multiple lines
355в†’  if (result.phases.length === 0) {
356в†’    const collectedPhases: Phase[] = [];
357в†’
358в†’    for (const line of lines) {
359в†’      if (
360в†’        line.includes("/spec") ||
361в†’        line.includes("/exec") ||
362в†’        line.includes("/test") ||
363в†’        line.includes("/qa")
364в†’      ) {
365в†’        const linePhases = parseWorkflowString(line);
366в†’        for (const phase of linePhases) {
367в†’          if (!collectedPhases.includes(phase)) {
368в†’            collectedPhases.push(phase);
369в†’          }
370в†’        }
371в†’      }
372в†’    }
373в†’
374в†’    if (collectedPhases.length > 0) {
375в†’      result.phases = collectedPhases;
376в†’      result.workflowString = collectedPhases.map((p) => `/${p}`).join(" в†’ ");
377в†’    }
378в†’  }
379в†’
380в†’  // If no phases found from lines, try full body
381в†’  if (result.phases.length === 0) {
382в†’    result.phases = parseWorkflowString(body);
383в†’  }
384в†’
385в†’  // Check for quality loop recommendation (if not already set by markers)
386в†’  if (!result.qualityLoop) {
387в†’    for (const pattern of QUALITY_LOOP_PATTERNS) {
388в†’      if (pattern.test(body)) {
389в†’        result.qualityLoop = true;
390в†’        break;
391в†’      }
392в†’    }
393в†’  }
394в†’
395в†’  return result;
396в†’}
397в†’
398в†’/**
399в†’ * Parse a solve comment to extract workflow information
400в†’ * @deprecated Use parseAssessWorkflow instead
401в†’ */
402в†’export function parseSolveWorkflow(body: string): AssessWorkflowResult {
403в†’  return parseAssessWorkflow(body);
404в†’}
405в†’
406в†’// в”Ђв”Ђв”Ђ Signal Conversion в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
407в†’
408в†’/**
409в†’ * Convert assess workflow result to phase signals
410в†’ */
411в†’export function assessWorkflowToSignals(
412в†’  workflow: AssessWorkflowResult,
413в†’): PhaseSignal[] {
414в†’  const signals: PhaseSignal[] = [];
415в†’
416в†’  for (const phase of workflow.phases) {
417в†’    signals.push({
418в†’      phase,
419в†’      source: "assess",
420в†’      confidence: "high",
421в†’      reason: `Recommended by /assess command: ${workflow.workflowString || phase}`,
422в†’    });
423в†’  }
424в†’
425в†’  if (workflow.qualityLoop) {
426в†’    signals.push({
427в†’      phase: "quality-loop",
428в†’      source: "assess",
429в†’      confidence: "high",
430в†’      reason: "Quality loop recommended by /assess command",
431в†’    });
432в†’  }
433в†’
434в†’  return signals;
435в†’}
436в†’
437в†’/**
438в†’ * Convert solve workflow result to phase signals
439в†’ *
440в†’ * Preserves "/solve" wording in reason strings for backward compatibility
441в†’ * with existing tests and consumers.
442в†’ *
443в†’ * @deprecated Use assessWorkflowToSignals instead
444в†’ */
445в†’export function solveWorkflowToSignals(
446в†’  workflow: AssessWorkflowResult,
447в†’): PhaseSignal[] {
448в†’  const signals: PhaseSignal[] = [];
449в†’
450в†’  for (const phase of workflow.phases) {
451в†’    signals.push({
452в†’      phase,
453в†’      source: "solve",
454в†’      confidence: "high",
455в†’      reason: `Recommended by /solve command: ${workflow.workflowString || phase}`,
456в†’    });
457в†’  }
458в†’
459в†’  if (workflow.qualityLoop) {
460в†’    signals.push({
461в†’      phase: "quality-loop",
462в†’      source: "solve",
463в†’      confidence: "high",
464в†’      reason: "Quality loop recommended by /solve command",
465в†’    });
466в†’  }
467в†’
468в†’  return signals;
469в†’}
470в†’
471в†’// в”Ђв”Ђв”Ђ Utility Functions в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
472в†’
473в†’/**
474в†’ * Check if assess/solve comment covers the current issue
475в†’ */
476в†’export function assessCoversIssue(
477в†’  workflow: AssessWorkflowResult,
478в†’  issueNumber: number,
479в†’): boolean {
480в†’  return workflow.issueNumbers.includes(issueNumber);
481в†’}
482в†’
483в†’/**
484в†’ * Check if solve comment covers the current issue
485в†’ * @deprecated Use assessCoversIssue instead
486в†’ */
487в†’export function solveCoversIssue(
488в†’  workflow: AssessWorkflowResult,
489в†’  issueNumber: number,
490в†’): boolean {
491в†’  return assessCoversIssue(workflow, issueNumber);
492в†’}
493в†’

  1в†’/**
  2в†’ * Phase detection and mapping utilities.
  3в†’ *
  4в†’ * Extracts label-to-phase detection logic and workflow parsing
  5в†’ * from the run command so it can be reused by batch-executor
  6в†’ * and other consumers.
  7в†’ *
