 73в†’    UI_LABELS.some((uiLabel) => label.includes(uiLabel)),
 74в†’  );
 75в†’
 76в†’  // Check for complex labels в†’ enable quality loop
 77в†’  const isComplex = lowerLabels.some((label) =>
 78в†’    COMPLEX_LABELS.some((complexLabel) => label.includes(complexLabel)),
 79в†’  );
 80в†’
 81в†’  // Check for security labels в†’ add security-review phase
